// Unit 20 — Voix Passive & Discours Indirect
// Passive voice and reported speech

export default {n:20,lang:"fr",srcLang:"en",track:"v2",title:"Voix Passive & Discours Indirect",sub:"Passive voice and reported speech",icon:"📰",level:"B1.4",color:"#7B5EE8",lessons:[
  {id:"fre20l1",title:"La Voix Passive",icon:"📰",xp:15,board:true,steps:[
        {type:"intro",title:"La Voix Passive",desc:"Learn how to form passive sentences in French using être + past participle, and how to introduce the agent with par.",goals:["Form passive sentences with être + past participle","Use par to introduce the agent","Understand past participle agreement in passive"]},
        {type:"teach",trg:"Le livre est lu par les étudiants",src:"The book is read by the students",pos:"noun",gender:"m",phonetic:"luh LEEVR eh LOO par leh zeh-too-DYON",note:"Passive voice: subject receives the action.\nêtre + past participle + par + agent.",example:"A: Qui lit ce livre en classe?\nB: Le livre est lu par les étudiants.\nA: Tous les étudiants le lisent?\nB: Oui, il est lu par tout le monde.",exampleSrc:"A: Who reads this book in class?\nB: The book is read by the students.\nA: All the students read it?\nB: Yes, it is read by everyone.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"La lettre est écrite par Marie",src:"The letter is written by Marie",pos:"noun",gender:"f",phonetic:"lah LETR eh teh-KREET par mah-REE",note:"Past participle agrees with subject in passive.\nécrite (feminine) agrees with la lettre.",example:"A: Qui écrit cette lettre?\nB: La lettre est écrite par Marie.\nA: Elle écrit souvent des lettres?\nB: Oui, beaucoup de lettres sont écrites par elle.",exampleSrc:"A: Who writes this letter?\nB: The letter is written by Marie.\nA: Does she write letters often?\nB: Yes, many letters are written by her.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"Les résultats sont annoncés par le professeur",src:"The results are announced by the teacher",pos:"noun",gender:"pl",phonetic:"leh reh-zool-TAH son tah-non-SEH par luh pro-feh-SUR",note:"Plural subject: sont + plural participle.\nannoncés agrees with les résultats (masc. pl.).",example:"A: Quand est-ce qu'on saura les résultats?\nB: Les résultats sont annoncés par le professeur demain.\nA: Il les annonce en classe?\nB: Oui, ils sont toujours annoncés en classe.",exampleSrc:"A: When will we know the results?\nB: The results are announced by the teacher tomorrow.\nA: Does he announce them in class?\nB: Yes, they are always announced in class.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"tip",title:"Forming the Passive Voice",deepDive:"Only transitive verbs (verbs with a direct object) can be made passive. You cannot make être, aller, venir, or other intransitive verbs passive. The agent (introduced by par) can be omitted if unknown or unimportant.",text:"Active: Marie écrit la lettre.\nPassive: La lettre est écrite par Marie.\n\nFormula: Subject + être (conjugated) + past participle + par + agent\n\nThe past participle AGREES with the subject:\n- Le gâteau est mangé (masc. sg.)\n- La porte est fermée (fem. sg.)\n- Les livres sont lus (masc. pl.)\n- Les lettres sont écrites (fem. pl.)"},
        {type:"mc",q:"Which is the correct passive form of 'Le chef prépare le repas'?",opts:["Le repas est préparé par le chef","Le repas a préparé par le chef","Le repas est préparer par le chef","Le repas est préparé le chef"],ans:"Le repas est préparé par le chef",hint:"The formula requires a conjugated auxiliary plus the participle form."},
        {type:"teach",trg:"Le pont est construit par les ouvriers",src:"The bridge is built by the workers",pos:"noun",gender:"m",phonetic:"luh PON eh kon-STRWEE par leh zoo-VREE-eh",note:"Construit: past participle of construire.\nNo extra agreement needed (masc. sg. subject).",example:"A: Ce pont est magnifique!\nB: Oui, il est construit par les meilleurs ouvriers.\nA: Combien de temps ça prend?\nB: Le pont est construit en deux ans.",exampleSrc:"A: This bridge is magnificent!\nB: Yes, it is built by the best workers.\nA: How long does it take?\nB: The bridge is built in two years.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"La chanson est chantée par tout le monde",src:"The song is sung by everyone",pos:"noun",gender:"f",phonetic:"lah shon-SON eh shon-TEH par too luh MOND",note:"Chantée: feminine agreement with la chanson.\nAdd -e for feminine, -s for plural, -es for fem. pl.",example:"A: Tu connais cette chanson?\nB: Bien sûr! Elle est chantée par tout le monde.\nA: Même les enfants la chantent?\nB: Oui, elle est chantée dans toutes les écoles.",exampleSrc:"A: Do you know this song?\nB: Of course! It is sung by everyone.\nA: Even the children sing it?\nB: Yes, it is sung in all the schools.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"fb",opts:["est","a","sont","fait"],hint:"Which form of the auxiliary works with a singular feminine subject?",s:"La maison {1} vendue par le propriétaire.",a:["est"]},
        {type:"mc",q:"'Les fleurs sont cueillies par les enfants.' What does this mean?",opts:["The flowers are picked by the children","The children are picking flowers","The flowers pick the children","The children have flowers"],ans:"The flowers are picked by the children",hint:"The subject receives the action in this construction."},
        {type:"fb",opts:["regardé","regarder","regarde","regardés"],hint:"The subject le match is masculine singular, so check the ending.",s:"Le match est {1} par des milliers de spectateurs.",a:["regardé"]},
        {type:"teach",trg:"La décision est prise par le directeur",src:"The decision is made by the director",pos:"noun",gender:"f",phonetic:"lah deh-see-ZYON eh PREEZ par luh dee-rek-TUR",note:"Prise: irregular past participle of prendre.\nFeminine form because la décision is feminine.",example:"A: Qui prend cette décision?\nB: La décision est prise par le directeur.\nA: Les employés ne décident pas?\nB: Non, toutes les décisions sont prises par lui.",exampleSrc:"A: Who makes this decision?\nB: The decision is made by the director.\nA: The employees don't decide?\nB: No, all decisions are made by him.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"mc",q:"Complete: 'Les portes _____ fermées à clé chaque soir.'",opts:["sont","est","ont","a"],ans:"sont",hint:"The subject is plural, so the auxiliary must match in number."},
        {type:"match",pairs:[
          {trg:"Le repas est préparé",src:"The meal is prepared"},
          {trg:"La porte est ouverte",src:"The door is opened"},
          {trg:"Les livres sont lus",src:"The books are read"},
          {trg:"Les lettres sont envoyées",src:"The letters are sent"}
        ]},
        {type:"fb",opts:["accompagnés","accompagné","accompagnée","accompagner"],hint:"The subject is masculine plural, so the ending must reflect that.",s:"Les enfants sont {1} par leurs parents.",a:["accompagnés"]},
        {type:"mc",q:"Which sentence is in the passive voice?",opts:["La voiture est réparée par le mécanicien","Le mécanicien répare la voiture","Le mécanicien a une voiture","La voiture roule vite"],ans:"La voiture est réparée par le mécanicien",hint:"Look for the auxiliary plus participle structure with par."},
        {type:"drag_fill",hint:"Plural subject needs plural auxiliary and plural participle.",s:"Les gâteaux {1} {2} par le boulanger chaque matin.",blanks:{"1":"sont","2":"préparés"},pool:["sont","préparés","est","préparé","ont","préparer"]},
        {type:"mc",q:"'La maison est construite par mon père.' The participle is feminine because...",opts:["it agrees with la maison","it agrees with mon père","all participles are feminine","it agrees with par"],ans:"it agrees with la maison",hint:"In passive, the participle always matches the grammatical subject."},
        {type:"fb",opts:["est","a","sont","font"],hint:"Singular feminine subject needs a singular auxiliary form.",s:"Cette chanson {1} connue dans le monde entier.",a:["est"]},
        {type:"mc",q:"Transform to passive: 'Le vent emporte les feuilles.'",opts:["Les feuilles sont emportées par le vent","Les feuilles ont emporté le vent","Le vent est emporté par les feuilles","Les feuilles est emportée par le vent"],ans:"Les feuilles sont emportées par le vent",hint:"The original direct object becomes the new subject of the sentence."}
  ]},
  {id:"fre20l2",title:"Le Passif aux Différents Temps",icon:"⏳",xp:15,board:true,steps:[
        {type:"intro",title:"Le Passif aux Différents Temps",desc:"Learn to form the passive voice in the passé composé, imparfait, future, and other tenses by conjugating être in the appropriate tense.",goals:["Form passive in passé composé (a été + participle)","Form passive in imparfait (était + participle)","Form passive in future (sera + participle)"]},
        {type:"teach",trg:"Le voleur a été arrêté par la police",src:"The thief was arrested by the police",pos:"noun",gender:"m",phonetic:"luh vo-LUR ah eh-TEH ah-reh-TEH par lah po-LEES",note:"Passé composé passive: avoir + été + participle.\nLe voleur a été arrêté. Never use avoir directly.",example:"A: Tu as entendu les nouvelles?\nB: Oui, le voleur a été arrêté par la police.\nA: Quand est-ce que c'est arrivé?\nB: Il a été arrêté hier soir vers minuit.",exampleSrc:"A: Did you hear the news?\nB: Yes, the thief was arrested by the police.\nA: When did it happen?\nB: He was arrested last night around midnight.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"La maison était entourée de fleurs",src:"The house was surrounded by flowers",pos:"noun",gender:"f",phonetic:"lah meh-ZON eh-TEH on-too-REH duh FLUR",note:"Imparfait passive: était/étaient + participle.\nUsed for descriptions and ongoing states in the past.",example:"A: Comment était la maison de ta grand-mère?\nB: La maison était entourée de fleurs.\nA: C'était joli?\nB: Oui, elle était aussi décorée avec soin.",exampleSrc:"A: What was your grandmother's house like?\nB: The house was surrounded by flowers.\nA: Was it pretty?\nB: Yes, it was also decorated with care.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"Le projet sera terminé demain",src:"The project will be finished tomorrow",pos:"noun",gender:"m",phonetic:"luh pro-ZHEH suh-RAH tehr-mee-NEH duh-MEN",note:"Future passive: sera/seront + participle.\nSera for singular, seront for plural subjects.",example:"A: Quand est-ce que le projet sera fini?\nB: Le projet sera terminé demain.\nA: Tu es sûr?\nB: Oui, il sera présenté au directeur vendredi.",exampleSrc:"A: When will the project be finished?\nB: The project will be finished tomorrow.\nA: Are you sure?\nB: Yes, it will be presented to the director on Friday.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"tip",title:"Passive Across Tenses",deepDive:"In the passé composé passive, you get a triple stack: auxiliary avoir + été + past participle. This looks complex but follows the same logic. The avoir never agrees (it always stays a/ont), and the final participle agrees with the subject.",text:"The key: conjugate ÊTRE in the desired tense.\n\nPresent: Le livre est lu.\nPassé composé: Le livre a été lu.\nImparfait: Le livre était lu.\nFutur simple: Le livre sera lu.\nPlus-que-parfait: Le livre avait été lu.\nConditionnel: Le livre serait lu.\n\nThe past participle always agrees with the subject."},
        {type:"mc",q:"'Le message a été envoyé.' What tense is the passive in?",opts:["Passé composé","Present","Imparfait","Future"],ans:"Passé composé",hint:"Look at the auxiliary structure: which combination signals a completed past action?"},
        {type:"fb",opts:["sera","est","était","a été"],hint:"The word demain tells you which tense to use here.",s:"La nouvelle {1} annoncée demain par le ministre.",a:["sera"]},
        {type:"teach",trg:"Les invités avaient été prévenus à l'avance",src:"The guests had been warned in advance",pos:"noun",gender:"pl",phonetic:"leh zan-vee-TEH ah-VEH eh-TEH preh-vuh-NOO ah lah-VONS",note:"Plus-que-parfait passive: avait/avaient + été + participle.\nFor events completed before another past event.",example:"A: Les invités savaient pour la surprise?\nB: Non, mais ils avaient été prévenus d'arriver tôt.\nA: Par qui?\nB: Ils avaient été prévenus par la sœur de Marie.",exampleSrc:"A: Did the guests know about the surprise?\nB: No, but they had been warned to arrive early.\nA: By whom?\nB: They had been warned by Marie's sister.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"Complete: 'Le château _____ construit au 15e siècle.'",opts:["a été","est","sera","avait"],ans:"a été",hint:"A historical event completed in the past needs the compound past form."},
        {type:"fb",opts:["bloquées","bloqué","bloqués","bloquer"],hint:"The subject les routes is feminine plural, so check agreement.",s:"Les routes étaient {1} par la neige chaque hiver.",a:["bloquées"]},
        {type:"match",pairs:[{trg:"est mangé",src:"is eaten (present)"},{trg:"a été mangé",src:"was eaten (passé composé)"},{trg:"était mangé",src:"was being eaten (imparfait)"},{trg:"sera mangé",src:"will be eaten (future)"}]},
        {type:"mc",q:"'Les documents seront vérifiés par l'équipe.' When will this happen?",opts:["In the future","In the past","Right now","It already happened"],ans:"In the future",hint:"The auxiliary form seront tells you the timeframe of this action."},
        {type:"drag_fill",hint:"Plus-que-parfait passive needs three elements in a specific order.",s:"Le tableau {1} {2} {3} par un artiste célèbre.",blanks:{"1":"avait","2":"été","3":"peint"},pool:["avait","été","peint","a","est","peinté"]},
        {type:"fb",opts:["sera","est","a été","était"],hint:"L'année prochaine indicates a timeframe that has not occurred yet.",s:"La loi {1} votée par le parlement l'année prochaine.",a:["sera"]},
        {type:"mc",q:"Which is correct for 'The windows were broken by the storm'?",opts:["Les fenêtres ont été cassées par la tempête","Les fenêtres est cassé par la tempête","Les fenêtres sera cassées par la tempête","Les fenêtres a été cassé par la tempête"],ans:"Les fenêtres ont été cassées par la tempête",hint:"Plural subject needs plural auxiliary, and the participle must agree."},
        {type:"drag_fill",hint:"A completed event in the past with a masculine singular subject.",s:"Ce film {1} {2} par des millions de personnes l'année dernière.",blanks:{"1":"a été","2":"vu"},pool:["a été","vu","est","sera","vue","voir"]},
        {type:"fb",opts:["publiés","publié","publiée","publier"],hint:"Les résultats is masculine plural, so match the ending accordingly.",s:"Les résultats seront {1} la semaine prochaine.",a:["publiés"]},
        {type:"mc",q:"'La ville était protégée par de hauts murs.' What tense is this?",opts:["Imparfait passive","Present passive","Passé composé passive","Future passive"],ans:"Imparfait passive",hint:"The auxiliary form était signals an ongoing or descriptive past state."},
        {type:"drag_fill",hint:"Hier soir indicates a completed action. The subject is masculine singular.",s:"Le discours {1} {2} par le président hier soir.",blanks:{"1":"a été","2":"prononcé"},pool:["a été","prononcé","est","sera","prononcée","avait"]},
        {type:"mc",q:"Transform 'On construira un nouveau pont' to passive future.",opts:["Un nouveau pont sera construit","Un nouveau pont a été construit","Un nouveau pont est construit","Un nouveau pont était construit"],ans:"Un nouveau pont sera construit",hint:"The original verb is in the future, so keep the same timeframe."}
  ]},
  {id:"fre20l3",title:"Quand Utiliser le Passif",icon:"📺",xp:15,board:true,steps:[
        {type:"intro",title:"Quand Utiliser le Passif",desc:"Learn when French uses the passive voice: in news reporting, formal contexts, and when the focus is on the action or recipient rather than the doer.",goals:["Recognize passive in news language","Understand when passive emphasizes the recipient","Know when the agent can be omitted"]},
        {type:"teach",trg:"Trois personnes ont été blessées dans l'accident",src:"Three people were injured in the accident",pos:"intj",gender:null,phonetic:"TWAH pehr-SON on teh-TEH bleh-SEH don lak-see-DON",note:"News language uses passive to focus on victims.\nThe agent (who caused it) is often unknown or omitted.",example:"A: Tu as vu les informations?\nB: Oui, trois personnes ont été blessées dans l'accident.\nA: C'est grave?\nB: Elles ont été transportées à l'hôpital.",exampleSrc:"A: Did you watch the news?\nB: Yes, three people were injured in the accident.\nA: Is it serious?\nB: They were taken to the hospital.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Le suspect a été identifié",src:"The suspect has been identified",pos:"noun",gender:"m",phonetic:"luh soos-PEH ah eh-TEH ee-don-tee-FYEH",note:"Formal and news contexts prefer passive.\nIt sounds more official than active voice.",example:"A: Est-ce qu'on a trouvé le coupable?\nB: Oui, le suspect a été identifié par la police.\nA: Il a été arrêté?\nB: Pas encore, mais il est recherché.",exampleSrc:"A: Did they find the culprit?\nB: Yes, the suspect has been identified by the police.\nA: Has he been arrested?\nB: Not yet, but he is being searched for.",funFact:"Cognate with English 'suspect has been identified'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"Ce tableau a été peint en 1889",src:"This painting was painted in 1889",pos:"intj",gender:null,phonetic:"suh tah-BLOH ah eh-TEH PAN on meel wee son kah-TRON-VEHN-NUF",note:"When the date or fact matters more than who did it.\nThe agent can be added with par if relevant.",example:"A: Ce tableau est magnifique!\nB: Il a été peint en 1889.\nA: Par qui?\nB: Il a été peint par un artiste impressionniste.",exampleSrc:"A: This painting is magnificent!\nB: It was painted in 1889.\nA: By whom?\nB: It was painted by an impressionist artist.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"tip",title:"When to Use the Passive Voice",deepDive:"French uses passive less frequently than English. In everyday speech, French prefers active constructions with on (On a volé mon vélo) or pronominal verbs (Ça se fait). The passive is most common in journalism, official documents, and formal writing.",text:"Use passive when:\n1. The doer is unknown: Le vélo a été volé. (The bike was stolen.)\n2. The doer is unimportant: La route est fermée. (The road is closed.)\n3. Focus is on the receiver: Le président a été élu. (The president was elected.)\n4. News and formal reports: Deux maisons ont été détruites.\n5. Scientific/academic writing: Cette théorie est acceptée.\n\nOmit the agent (par...) when it adds nothing."},
        {type:"mc",q:"Why would a news report say 'Le bâtiment a été évacué' instead of the active form?",opts:["To focus on what happened to the building","To focus on who evacuated it","Because passive is always better","Because active voice is incorrect"],ans:"To focus on what happened to the building",hint:"News reports prioritize the event and its impact on the receiver."},
        {type:"teach",trg:"Les billets sont vendus en ligne",src:"The tickets are sold online",pos:"noun",gender:"pl",phonetic:"leh bee-YEH son von-DOO on LEEN-yuh",note:"Agent omitted because it is obvious or unimportant.\nFocus is on the tickets and how to get them.",example:"A: Où est-ce qu'on achète les billets?\nB: Les billets sont vendus en ligne.\nA: On ne peut pas les acheter au guichet?\nB: Non, ils sont uniquement vendus sur le site.",exampleSrc:"A: Where do you buy the tickets?\nB: The tickets are sold online.\nA: Can't you buy them at the counter?\nB: No, they are only sold on the website.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"fb",opts:["est","a été","sera","était"],hint:"A general fact about the museum's current schedule needs present tense.",s:"Le musée {1} fermé le lundi.",a:["est"]},
        {type:"mc",q:"Which sentence uses passive to report unknown information?",opts:["Mon portefeuille a été volé","J'ai perdu mon portefeuille","Quelqu'un a volé mon portefeuille","Je cherche mon portefeuille"],ans:"Mon portefeuille a été volé",hint:"When you do not know the person responsible, the action falls on the object."},
        {type:"teach",trg:"L'école sera rénovée l'année prochaine",src:"The school will be renovated next year",pos:"noun",gender:"m",phonetic:"leh-KOL suh-RAH reh-no-VEH lah-NEH pro-SHEN",note:"Future passive for announcements and plans.\nCommon in official communication and news.",example:"A: L'école est un peu vieille, non?\nB: Oui, mais elle sera rénovée l'année prochaine.\nA: Qui va payer les travaux?\nB: Les travaux seront financés par la mairie.",exampleSrc:"A: The school is a bit old, right?\nB: Yes, but it will be renovated next year.\nA: Who will pay for the work?\nB: The work will be funded by the city hall.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"match",pairs:[
          {trg:"Le voleur a été arrêté",src:"Crime report"},
          {trg:"Ce vin est produit en Bourgogne",src:"Product description"},
          {trg:"La loi sera votée demain",src:"Political news"},
          {trg:"Le pont a été construit en 1900",src:"Historical fact"}
        ]},
        {type:"mc",q:"'Deux personnes ont été hospitalisées.' Why is passive used here?",opts:["The focus is on the people affected","To sound casual","The speaker caused the hospitalization","Passive is required for all medical topics"],ans:"The focus is on the people affected",hint:"The construction puts the emphasis on who was impacted by the event."},
        {type:"fb",opts:["a été","est","sera","avait été"],hint:"The word hier tells you this happened in the recent completed past.",s:"Cette décision {1} prise par le conseil hier.",a:["a été"]},
        {type:"drag_fill",hint:"A future event with a masculine singular subject.",s:"Le nouveau stade {1} {2} en 2028.",blanks:{"1":"sera","2":"inauguré"},pool:["sera","inauguré","a été","est","inaugurés","inaugurée"]},
        {type:"mc",q:"In which context is the passive LEAST natural in French?",opts:["Casual conversation between friends","A newspaper headline","A police report","A scientific article"],ans:"Casual conversation between friends",hint:"Everyday spoken French tends to prefer a different construction."},
        {type:"fb",opts:["affichés","affiché","affichée","afficher"],hint:"Les résultats is masculine plural. Match the participle ending.",s:"Les résultats de l'examen sont {1} sur le site internet.",a:["affichés"]},
        {type:"mc",q:"'Le nouveau directeur a été nommé ce matin.' What is emphasized?",opts:["The new director and the appointment","The person who appointed the director","The morning","The old director"],ans:"The new director and the appointment",hint:"The subject of a passive sentence receives the spotlight."},
        {type:"drag_fill",hint:"Plural feminine subject in the completed past needs three specific elements.",s:"Cinq maisons {1} {2} {3} par l'incendie.",blanks:{"1":"ont","2":"été","3":"détruites"},pool:["ont","été","détruites","est","détruit","a"]},
        {type:"mc",q:"Rewrite in passive: 'Le facteur distribue le courrier.'",opts:["Le courrier est distribué par le facteur","Le facteur est distribué par le courrier","Le courrier a distribué le facteur","Le courrier distribue le facteur"],ans:"Le courrier est distribué par le facteur",hint:"The original direct object becomes the subject receiving the action."}
  ]},
  {id:"fre20l4",title:"Éviter le Passif",icon:"🔄",xp:15,board:true,steps:[
        {type:"intro",title:"Éviter le Passif",desc:"Learn the French alternatives to passive voice: on + active verb, se faire + infinitive, and pronominal constructions. These are often preferred in everyday speech.",goals:["Use on + active verb as passive alternative","Use se faire + infinitive for passive experiences","Use pronominal verbs as passive alternatives"]},
        {type:"teach",trg:"On parle français ici",src:"French is spoken here",pos:"verb",gender:null,phonetic:"on PARL fron-SEH ee-SEE",note:"On + active verb is the most common alternative.\nMore natural than Le français est parlé ici.",example:"A: Est-ce qu'on parle anglais dans ce magasin?\nB: Non, on parle français ici.\nA: Et dans le restaurant à côté?\nB: Là aussi, on parle uniquement français.",exampleSrc:"A: Is English spoken in this shop?\nB: No, French is spoken here.\nA: And in the restaurant next door?\nB: There too, only French is spoken.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"On a volé mon vélo",src:"My bike was stolen",pos:"intj",gender:null,phonetic:"on ah vo-LEH mon veh-LO",note:"On a volé = someone stole (identity unknown).\nMuch more natural than Mon vélo a été volé.",example:"A: Pourquoi tu marches aujourd'hui?\nB: On a volé mon vélo hier soir.\nA: Tu as appelé la police?\nB: Oui, on m'a dit de déposer une plainte.",exampleSrc:"A: Why are you walking today?\nB: My bike was stolen last night.\nA: Did you call the police?\nB: Yes, I was told to file a complaint.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Ça se voit",src:"That shows / That can be seen",pos:"verb",gender:null,phonetic:"sah suh VWAH",note:"Pronominal passive: se + verb.\nCa se voit, ça se fait, ça se dit, ça se mange.",example:"A: J'ai pleuré toute la nuit.\nB: Oui, ça se voit un peu.\nA: Vraiment? C'est si visible?\nB: Tes yeux sont un peu rouges, ça se voit.",exampleSrc:"A: I cried all night.\nB: Yes, it shows a little.\nA: Really? Is it that visible?\nB: Your eyes are a bit red, it shows.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Three Ways to Avoid Passive",deepDive:"Se faire + infinitive often implies something unpleasant happening to the subject. Elle s'est fait voler son sac (She had her bag stolen). Il s'est fait arrêter (He got himself arrested). It can also be neutral: Elle s'est fait couper les cheveux (She got her hair cut).",text:"1. On + active verb (most common):\n   Le français est parlé ici → On parle français ici.\n\n2. Pronominal (se + verb):\n   Ce plat est mangé froid → Ce plat se mange froid.\n   Common: ça se fait, ça se dit, ça se voit\n\n3. Se faire + infinitive (something happens TO you):\n   Il a été licencié → Il s'est fait licencier.\n   Elle a été voler son sac → Elle s'est fait voler son sac.\n\nFrench speakers prefer these in conversation.\nPassive voice is reserved for formal contexts."},
        {type:"mc",q:"Which is the most natural way to say 'French is spoken here' in everyday French?",opts:["On parle français ici","Le français est parlé ici","Le français se parle ici","Français est parlé ici"],ans:"On parle français ici",hint:"Everyday conversation favors the simple pronoun plus active verb form."},
        {type:"teach",trg:"Ce vin se boit frais",src:"This wine is drunk chilled",pos:"intj",gender:null,phonetic:"suh VAN suh BWAH FREH",note:"Se boire, se manger, se servir: pronominal passives.\nUsed for general truths about food and drink.",example:"A: Comment on boit ce vin?\nB: Ce vin se boit frais.\nA: Avec quoi il se mange?\nB: Il se boit bien avec du poisson.",exampleSrc:"A: How do you drink this wine?\nB: This wine is drunk chilled.\nA: What does it go with?\nB: It goes well with fish.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Elle s'est fait voler son sac",src:"She had her bag stolen",pos:"verb",gender:null,phonetic:"el seh FEH vo-LEH son SAK",note:"Se faire + infinitive: something happens to you.\nOften for unpleasant events. Very common in speech.",example:"A: Pourquoi Julie est triste?\nB: Elle s'est fait voler son sac dans le métro.\nA: Oh non! Il y avait quoi dedans?\nB: Son téléphone et ses clés. Elle s'est fait avoir.",exampleSrc:"A: Why is Julie sad?\nB: She had her bag stolen on the metro.\nA: Oh no! What was inside?\nB: Her phone and her keys. She got tricked.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"fb",opts:["fait","faire","a fait","faisait"],hint:"The pronominal construction needs the present tense third person form.",s:"Ça ne se {1} pas en France.",a:["fait"]},
        {type:"mc",q:"Rewrite 'Mon portefeuille a été volé' using on:",opts:["On a volé mon portefeuille","On se volé mon portefeuille","On fait voler mon portefeuille","On est volé mon portefeuille"],ans:"On a volé mon portefeuille",hint:"Replace the passive subject with on and put the verb in active form."},
        {type:"match",pairs:[
          {trg:"On parle anglais ici",src:"English is spoken here"},
          {trg:"Ce plat se mange chaud",src:"This dish is eaten hot"},
          {trg:"Il s'est fait arrêter",src:"He got arrested"},
          {trg:"Ça se dit souvent",src:"That is often said"}
        ]},
        {type:"mc",q:"'Ce mot ne se dit plus.' What construction is this?",opts:["Pronominal passive (se + verb)","On + active verb","Se faire + infinitive","Standard passive with être"],ans:"Pronominal passive (se + verb)",hint:"The reflexive pronoun before the verb signals this type of construction."},
        {type:"fb",opts:["licencier","licencié","licencie","licenciée"],hint:"After se faire, the verb stays in its base unconjugated form.",s:"Il s'est fait {1} par son patron.",a:["licencier"]},
        {type:"drag_fill",hint:"The most natural spoken alternative uses a simple pronoun plus present tense.",s:"{1} {2} que ce restaurant est très bon.",blanks:{"1":"On","2":"dit"},pool:["On","dit","Il","est","se","fait"]},
        {type:"mc",q:"Which uses se faire + infinitive correctly?",opts:["Je me suis fait couper les cheveux","J'ai été coupé les cheveux","On m'a été coupé les cheveux","Je suis fait couper les cheveux"],ans:"Je me suis fait couper les cheveux",hint:"Se faire conjugates as a reflexive verb in compound tenses."},
        {type:"fb",opts:["lit","lire","lu","lisent"],hint:"Present tense pronominal form with a singular subject needs third person.",s:"Ce livre se {1} en une journée.",a:["lit"]},
        {type:"mc",q:"Which alternative to passive sounds most formal?",opts:["Le document a été signé par le ministre","On a signé le document","Le document se signe demain","Le ministre s'est fait signer le document"],ans:"Le document a été signé par le ministre",hint:"The traditional construction with the auxiliary and par is the most formal register."},
        {type:"drag_fill",hint:"The reflexive compound past with the base form of the main verb.",s:"Elle {1} {2} {3} son téléphone dans le bus.",blanks:{"1":"s'est","2":"fait","3":"voler"},pool:["s'est","fait","voler","a été","volé","se"]},
        {type:"mc",q:"How would you naturally say 'That isn't done in France' in conversation?",opts:["Ça ne se fait pas en France","Cela n'est pas fait en France","On ne fait pas cela en France","C'est pas fait en France"],ans:"Ça ne se fait pas en France",hint:"For general social norms, the pronominal form is the most idiomatic."}
  ]},
  {id:"fre20l5",title:"Discours Indirect: Présent",icon:"💬",xp:15,board:true,steps:[
        {type:"intro",title:"Discours Indirect: Présent",desc:"Learn to report what someone says using il/elle dit que... with present tense. No tense change is needed when the reporting verb is in the present.",goals:["Convert direct speech to indirect with dit que","Handle declarative and imperative reported speech","Understand pronoun and possessive shifts"]},
        {type:"teach",trg:"Il dit qu'il est fatigué",src:"He says (that) he is tired",pos:"verb",gender:null,phonetic:"eel DEE keel eh fah-tee-GEH",note:"Direct: Il dit: Je suis fatigué.\nIndirect: Il dit qu'il est fatigué.\nJe becomes il, que links the clauses.",example:"A: Paul a l'air fatigué.\nB: Oui, il dit qu'il est fatigué.\nA: Il travaille trop?\nB: Il dit qu'il ne dort pas assez.",exampleSrc:"A: Paul looks tired.\nB: Yes, he says he's tired.\nA: Does he work too much?\nB: He says he doesn't sleep enough.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Elle dit qu'elle aime le chocolat",src:"She says (that) she likes chocolate",pos:"verb",gender:null,phonetic:"el DEE kel EM luh sho-ko-LAH",note:"Direct: Elle dit: J'aime le chocolat.\nIndirect: Elle dit qu'elle aime le chocolat.\nJ' becomes elle after the reporting verb.",example:"A: Marie veut un dessert?\nB: Elle dit qu'elle aime le chocolat.\nA: On lui achète une mousse au chocolat?\nB: Bonne idée! Elle dit qu'elle adore ça.",exampleSrc:"A: Does Marie want a dessert?\nB: She says she likes chocolate.\nA: Should we get her a chocolate mousse?\nB: Good idea! She says she loves that.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Ils disent que le film est excellent",src:"They say (that) the film is excellent",pos:"verb",gender:null,phonetic:"eel DEEZ kuh luh FEELM eh tek-seh-LON",note:"Disent (third person plural) + que.\nNo tense change when reporting verb is present.",example:"A: On va voir ce film ce soir?\nB: Oui, ils disent que le film est excellent.\nA: Qui dit ça?\nB: Tout le monde dit que c'est le meilleur de l'année.",exampleSrc:"A: Shall we see this film tonight?\nB: Yes, they say the film is excellent.\nA: Who says that?\nB: Everyone says it's the best of the year.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Discours Indirect: Present Tense",deepDive:"Que becomes qu' before a vowel sound: Il dit qu'il... Elle dit qu'elle... But: Il dit que le film... (no elision before le). The conjunction que is required in French, unlike English where 'that' is often optional.",text:"When the reporting verb is in the PRESENT tense (dit, disent), no tense change occurs in the reported clause.\n\nDirect → Indirect:\nIl dit: \"Je suis content.\" → Il dit qu'il est content.\nElle dit: \"J'ai faim.\" → Elle dit qu'elle a faim.\nIls disent: \"Nous partons.\" → Ils disent qu'ils partent.\n\nKey changes:\n- Quotation marks and colon disappear\n- que introduces the reported clause\n- Pronouns shift (je→il/elle, nous→ils/elles)\n- Possessives shift (mon→son, notre→leur)"},
        {type:"mc",q:"Convert to indirect: 'Marie dit: \"Je suis prête.\"'",opts:["Marie dit qu'elle est prête","Marie dit que je suis prête","Marie dit qu'elle a prête","Marie dit elle est prête"],ans:"Marie dit qu'elle est prête",hint:"The first person pronoun shifts to match the subject of the reporting verb."},
        {type:"fb",opts:["qu'il","que il","qu'elle","que"],hint:"The conjunction must elide before the pronoun that replaces je.",s:"Il dit {1} a un nouveau travail.",a:["qu'il"]},
        {type:"teach",trg:"Elle dit que son frère habite à Lyon",src:"She says (that) her brother lives in Lyon",pos:"verb",gender:null,phonetic:"el DEE kuh son FREHR ah-BEET ah lee-ON",note:"Direct: Elle dit: Mon frère habite à Lyon.\nIndirect: Elle dit que son frère habite à Lyon.\nMon becomes son (her).",example:"A: Tu connais le frère de Sophie?\nB: Non, mais elle dit que son frère habite à Lyon.\nA: Il travaille là-bas?\nB: Elle dit qu'il est ingénieur.",exampleSrc:"A: Do you know Sophie's brother?\nB: No, but she says her brother lives in Lyon.\nA: Does he work there?\nB: She says he's an engineer.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"Convert: 'Pierre dit: \"Nous aimons le tennis.\"'",opts:["Pierre dit qu'ils aiment le tennis","Pierre dit que nous aimons le tennis","Pierre dit qu'il aime le tennis","Pierre dit ils aiment le tennis"],ans:"Pierre dit qu'ils aiment le tennis",hint:"When Pierre says nous, he means himself and others, so it shifts to ils."},
        {type:"teach",trg:"Il dit de fermer la porte",src:"He says to close the door",pos:"verb",gender:null,phonetic:"eel DEE duh fehr-MEH lah PORT",note:"Imperative in indirect speech: dit DE + infinitive.\nDirect: Il dit: Fermez la porte!\nIndirect: Il dit de fermer la porte.",example:"A: Qu'est-ce que le professeur dit?\nB: Il dit de fermer la porte.\nA: Et les fenêtres?\nB: Il dit aussi d'ouvrir les fenêtres.",exampleSrc:"A: What does the teacher say?\nB: He says to close the door.\nA: And the windows?\nB: He also says to open the windows.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"fb",opts:["de","que","qu'","à"],hint:"When reporting a command, the linking word before the infinitive is specific.",s:"Elle dit {1} faire nos devoirs.",a:["de"]},
        {type:"match",pairs:[
          {trg:"Il dit: \"Je suis content.\"",src:"Il dit qu'il est content."},
          {trg:"Elle dit: \"J'ai faim.\"",src:"Elle dit qu'elle a faim."},
          {trg:"Il dit: \"Sortez!\"",src:"Il dit de sortir."},
          {trg:"Elle dit: \"Mon chat dort.\"",src:"Elle dit que son chat dort."}
        ]},
        {type:"mc",q:"How do you report 'Taisez-vous!' indirectly?",opts:["Il dit de se taire","Il dit qu'il se tait","Il dit que taisez-vous","Il dit de taisez-vous"],ans:"Il dit de se taire",hint:"Commands become de plus the base verb form in reported speech."},
        {type:"fb",opts:["que","qu'","de","qui"],hint:"Before le, there is no vowel to trigger shortening of the conjunction.",s:"Ils disent {1} le restaurant est fermé.",a:["que"]},
        {type:"drag_fill",hint:"The conjunction shortens before a vowel, then the shifted pronoun follows.",s:"Elle dit {1} {2} veut partir demain.",blanks:{"1":"qu'","2":"elle"},pool:["qu'","elle","que","il","de","je"]},
        {type:"mc",q:"Convert: 'Les enfants disent: \"Nous avons soif.\"'",opts:["Les enfants disent qu'ils ont soif","Les enfants disent que nous avons soif","Les enfants disent qu'ils avons soif","Les enfants dit qu'ils ont soif"],ans:"Les enfants disent qu'ils ont soif",hint:"Shift nous to the third person plural and conjugate accordingly."},
        {type:"fb",opts:["prendre","prend","pris","prenez"],hint:"After the linking word de, the verb stays in its unconjugated base form.",s:"Le médecin dit de {1} ces médicaments.",a:["prendre"]},
        {type:"mc",q:"'Il dit: \"Ma sœur est malade.\"' becomes:",opts:["Il dit que sa sœur est malade","Il dit que ma sœur est malade","Il dit qu'elle sœur est malade","Il dit de sa sœur est malade"],ans:"Il dit que sa sœur est malade",hint:"The possessive shifts from first person to third person to match the speaker."},
        {type:"drag_fill",hint:"Possessive shifts from mes to the third person form for plural.",s:"Elle dit {1} {2} enfants {3} à l'école.",blanks:{"1":"que","2":"ses","3":"sont"},pool:["que","ses","sont","qu'","mes","est"]}
  ]},
  {id:"fre20l6",title:"Discours Indirect: Passé",icon:"🕰️",xp:15,board:true,steps:[
        {type:"intro",title:"Discours Indirect: Passé",desc:"When the reporting verb is in the past (il a dit que...), tenses shift in the reported clause. This is called la concordance des temps.",goals:["Apply tense shifts when reporting verb is past","Shift present to imparfait, PC to plus-que-parfait","Shift future to conditional"]},
        {type:"teach",trg:"Il a dit qu'il était fatigué",src:"He said (that) he was tired",pos:"verb",gender:null,phonetic:"eel ah DEE keel eh-TEH fah-tee-GEH",note:"Present → Imparfait when reporting verb is past.\nDirect: Il a dit: Je suis fatigué.\nIndirect: Il a dit qu'il était fatigué.",example:"A: Qu'est-ce que Pierre a dit?\nB: Il a dit qu'il était fatigué.\nA: C'est tout?\nB: Non, il a aussi dit qu'il voulait dormir.",exampleSrc:"A: What did Pierre say?\nB: He said he was tired.\nA: Is that all?\nB: No, he also said he wanted to sleep.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Elle a dit qu'elle avait fini",src:"She said (that) she had finished",pos:"verb",gender:null,phonetic:"el ah DEE kel ah-VEH fee-NEE",note:"Passé composé → Plus-que-parfait.\nDirect: Elle a dit: J'ai fini.\nIndirect: Elle a dit qu'elle avait fini.",example:"A: Marie a terminé son projet?\nB: Oui, elle a dit qu'elle avait fini hier.\nA: Déjà? C'est rapide!\nB: Elle a dit qu'elle avait travaillé tout le week-end.",exampleSrc:"A: Did Marie finish her project?\nB: Yes, she said she had finished yesterday.\nA: Already? That's fast!\nB: She said she had worked all weekend.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Il a dit qu'il viendrait demain",src:"He said (that) he would come tomorrow",pos:"verb",gender:null,phonetic:"eel ah DEE keel vyen-DREH duh-MEN",note:"Futur → Conditionnel when reporting verb is past.\nDirect: Il a dit: Je viendrai demain.\nIndirect: Il a dit qu'il viendrait demain.",example:"A: Thomas va venir à la fête?\nB: Il a dit qu'il viendrait demain.\nA: Il est sûr?\nB: Il a dit qu'il essaierait d'arriver tôt.",exampleSrc:"A: Will Thomas come to the party?\nB: He said he would come tomorrow.\nA: Is he sure?\nB: He said he would try to arrive early.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"La Concordance des Temps",deepDive:"This system is called la concordance des temps (sequence of tenses). It works the same as English backshift: 'I am' becomes 'he said he was'. The imparfait and conditionnel do not shift because they are already 'past-compatible' tenses.",text:"When the reporting verb is PAST (a dit, disait, avait dit):\n\nPrésent → Imparfait\n  Je suis content → Il a dit qu'il était content.\n\nPassé composé → Plus-que-parfait\n  J'ai mangé → Il a dit qu'il avait mangé.\n\nFutur → Conditionnel\n  Je partirai → Il a dit qu'il partirait.\n\nImparfait → Imparfait (no change)\n  J'avais faim → Il a dit qu'il avait faim.\n\nConditionnel → Conditionnel (no change)\n  Je voudrais → Il a dit qu'il voudrait."},
        {type:"mc",q:"Il a dit: 'Je mange une pomme.' → Il a dit qu'il _____ une pomme.",opts:["mangeait","mange","a mangé","mangera"],ans:"mangeait",hint:"The present tense shifts one step back when the reporting verb is past."},
        {type:"fb",opts:["était","est","sera","a été"],hint:"Passé composé shifts to a compound past tense using the imparfait auxiliary.",s:"Elle a dit qu'elle {1} partie la veille.",a:["était"]},
        {type:"teach",trg:"Ils ont dit qu'ils ne pouvaient pas venir",src:"They said (that) they couldn't come",pos:"verb",gender:null,phonetic:"eel zon DEE keel nuh poo-VEH pah vuh-NEER",note:"Peuvent (present) → pouvaient (imparfait).\nThe modal verb shifts just like any other verb.",example:"A: Les voisins viennent au dîner?\nB: Non, ils ont dit qu'ils ne pouvaient pas venir.\nA: Pourquoi?\nB: Ils ont dit qu'ils avaient déjà des plans.",exampleSrc:"A: Are the neighbors coming to dinner?\nB: No, they said they couldn't come.\nA: Why?\nB: They said they already had plans.",funFact:"A -ir verb. Many follow the -ir pattern with -iss- in plural forms."},
        {type:"mc",q:"Il a dit: 'J'ai vu le film.' becomes:",opts:["Il a dit qu'il avait vu le film","Il a dit qu'il a vu le film","Il a dit qu'il voyait le film","Il a dit qu'il verra le film"],ans:"Il a dit qu'il avait vu le film",hint:"A completed past action shifts to the tense that expresses an earlier past."},
        {type:"match",pairs:[
          {trg:"présent → imparfait",src:"je mange → il a dit qu'il mangeait"},
          {trg:"passé composé → PQP",src:"j'ai vu → il a dit qu'il avait vu"},
          {trg:"futur → conditionnel",src:"je partirai → il a dit qu'il partirait"},
          {trg:"imparfait → imparfait",src:"j'avais faim → il a dit qu'il avait faim"}
        ]},
        {type:"fb",opts:["viendrait","viendra","venait","est venu"],hint:"The future tense shifts to its conditional form in past reported speech.",s:"Il a dit qu'il {1} le lendemain.",a:["viendrait"]},
        {type:"teach",trg:"Elle a dit qu'elle avait toujours voulu visiter Paris",src:"She said she had always wanted to visit Paris",pos:"verb",gender:null,phonetic:"el ah DEE kel ah-VEH too-ZHOOR voo-LOO vee-zee-TEH pah-REE",note:"Complex backshift: a voulu → avait voulu.\nMultiple tense shifts in the same conversation.",example:"A: Sophie va enfin à Paris!\nB: Oui, elle a dit qu'elle avait toujours voulu y aller.\nA: Combien de temps elle reste?\nB: Elle a dit qu'elle resterait deux semaines.",exampleSrc:"A: Sophie is finally going to Paris!\nB: Yes, she said she had always wanted to go there.\nA: How long is she staying?\nB: She said she would stay two weeks.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"drag_fill",hint:"Passé composé shifts to plus-que-parfait in reported speech. Pronoun + auxiliary + participle.",s:"Il a dit {1} {2} {3} le bus.",blanks:{"1":"qu'il","2":"avait","3":"raté"},pool:["qu'il","avait","raté","qu'elle","a","manqué"]},
        {type:"mc",q:"'Elle a dit: \"Je vais acheter une voiture.\"' becomes:",opts:["Elle a dit qu'elle allait acheter une voiture","Elle a dit qu'elle va acheter une voiture","Elle a dit qu'elle irait acheter une voiture","Elle a dit qu'elle achetait une voiture"],ans:"Elle a dit qu'elle allait acheter une voiture",hint:"The near future (aller + infinitive) shifts aller to its imparfait form."},
        {type:"fb",opts:["avaient","ont","étaient","auraient"],hint:"The auxiliary for a shifted compound past tense needs the imparfait form.",s:"Ils ont dit qu'ils {1} déjà mangé.",a:["avaient"]},
        {type:"mc",q:"Which tense does NOT change in past reported speech?",opts:["Imparfait","Présent","Futur","Passé composé"],ans:"Imparfait",hint:"One of these tenses is already in a past-compatible form and stays the same."},
        {type:"drag_fill",hint:"Present shifts back one step, and possessives shift from first to third person.",s:"Elle a dit {1} {2} très contente de {3} nouvelle maison.",blanks:{"1":"qu'elle","2":"était","3":"sa"},pool:["qu'elle","était","sa","qu'il","est","ma"]},
        {type:"mc",q:"Il a dit: 'Je ferai les courses.' In indirect speech:",opts:["Il a dit qu'il ferait les courses","Il a dit qu'il fait les courses","Il a dit qu'il faisait les courses","Il a dit qu'il a fait les courses"],ans:"Il a dit qu'il ferait les courses",hint:"The simple future form of faire shifts to its conditional equivalent."}
  ]},
  {id:"fre20l7",title:"Questions Indirectes",icon:"❓",xp:15,board:true,steps:[
        {type:"intro",title:"Questions Indirectes",desc:"Learn to report questions using il demande si (yes/no questions), ce que (what as object), ce qui (what as subject), and other question words.",goals:["Report yes/no questions with si","Report information questions with ce que/ce qui","Use indirect question word order (no inversion)"]},
        {type:"teach",trg:"Il demande si tu viens ce soir",src:"He asks if/whether you're coming tonight",pos:"verb",gender:null,phonetic:"eel duh-MOND see too VYEN suh SWAHR",note:"Yes/No questions → si (if/whether).\nDirect: Tu viens ce soir?\nIndirect: Il demande si tu viens ce soir.",example:"A: Marc a appelé.\nB: Qu'est-ce qu'il veut?\nA: Il demande si tu viens ce soir.\nB: Dis-lui que je viendrai vers huit heures.",exampleSrc:"A: Marc called.\nB: What does he want?\nA: He asks if you're coming tonight.\nB: Tell him I'll come around eight.",funFact:"A -ir verb. Many follow the -ir pattern with -iss- in plural forms."},
        {type:"teach",trg:"Elle demande ce que tu fais",src:"She asks what you're doing",pos:"verb",gender:null,phonetic:"el duh-MOND suh kuh too FEH",note:"Qu'est-ce que (what, object) → ce que.\nDirect: Qu'est-ce que tu fais?\nIndirect: Elle demande ce que tu fais.",example:"A: Ta mère a téléphoné.\nB: Qu'est-ce qu'elle voulait?\nA: Elle demande ce que tu fais ce week-end.\nB: Dis-lui que je suis occupé samedi.",exampleSrc:"A: Your mother called.\nB: What did she want?\nA: She asks what you're doing this weekend.\nB: Tell her I'm busy Saturday.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Je ne sais pas ce qui se passe",src:"I don't know what's happening",pos:"verb",gender:null,phonetic:"zhuh nuh SEH pah suh kee suh PAHS",note:"Qu'est-ce qui (what, subject) → ce qui.\nDirect: Qu'est-ce qui se passe?\nIndirect: Je ne sais pas ce qui se passe.",example:"A: Pourquoi tout le monde court?\nB: Je ne sais pas ce qui se passe.\nA: Il y a peut-être un problème?\nB: Je vais demander ce qui est arrivé.",exampleSrc:"A: Why is everyone running?\nB: I don't know what's happening.\nA: Maybe there's a problem?\nB: I'll ask what happened.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Indirect Questions: The Full System",deepDive:"The distinction between ce qui and ce que mirrors qui/que in relative clauses. Ce qui replaces a subject (what is happening = ce qui se passe), while ce que replaces an object (what you want = ce que tu veux). If you can insert il/elle after, use ce que. If not, use ce qui.",text:"Yes/No questions → si:\n  Tu viens? → Il demande si tu viens.\n\nQu'est-ce que (what, object) → ce que:\n  Qu'est-ce que tu fais? → Il demande ce que tu fais.\n\nQu'est-ce qui (what, subject) → ce qui:\n  Qu'est-ce qui se passe? → Il demande ce qui se passe.\n\nOther question words stay the same:\n  Où habites-tu? → Il demande où tu habites.\n  Quand pars-tu? → Il demande quand tu pars.\n  Pourquoi pleures-tu? → Il demande pourquoi tu pleures.\n  Comment vas-tu? → Il demande comment tu vas.\n\nCRITICAL: No inversion in indirect questions!\n  Il demande où tu habites. (NOT: où habites-tu)"},
        {type:"mc",q:"Convert: 'Est-ce que tu parles français?' → Il demande _____",opts:["si tu parles français","que tu parles français","ce que tu parles français","est-ce que tu parles français"],ans:"si tu parles français",hint:"For yes/no questions, the linking word is a two-letter conjunction."},
        {type:"fb",opts:["où","si","ce que","comment"],hint:"The original question was about a location or place.",s:"Elle demande {1} j'ai mis les clés.",a:["où"]},
        {type:"teach",trg:"Il veut savoir combien ça coûte",src:"He wants to know how much it costs",pos:"verb",gender:null,phonetic:"eel VUH sah-VWAHR kon-BYEN sah KOOT",note:"Combien stays the same in indirect questions.\nNo inversion: combien ça coûte (not combien coûte-t-il).",example:"A: Regarde cette montre!\nB: Elle est belle. Il veut savoir combien ça coûte.\nA: C'est marqué 250 euros.\nB: Il demande s'il y a une réduction.",exampleSrc:"A: Look at this watch!\nB: It's beautiful. He wants to know how much it costs.\nA: It says 250 euros.\nB: He asks if there's a discount.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Qu'est-ce qui fait ce bruit?' becomes:",opts:["Il demande ce qui fait ce bruit","Il demande ce que fait ce bruit","Il demande si fait ce bruit","Il demande qu'est-ce qui fait ce bruit"],ans:"Il demande ce qui fait ce bruit",hint:"When the what replaces the subject of the action, use the subject form."},
        {type:"fb",opts:["ce qu'","ce qui","si","qu'est-ce qu'"],hint:"What she wants: she is the subject, the what is the object of vouloir.",s:"Je ne sais pas {1} elle veut pour son anniversaire.",a:["ce qu'"]},
        {type:"match",pairs:[
          {trg:"Est-ce que tu viens?",src:"Il demande si tu viens."},
          {trg:"Qu'est-ce que tu veux?",src:"Il demande ce que tu veux."},
          {trg:"Où habites-tu?",src:"Il demande où tu habites."},
          {trg:"Qu'est-ce qui est arrivé?",src:"Il demande ce qui est arrivé."}
        ]},
        {type:"teach",trg:"Je me demande pourquoi il est parti",src:"I wonder why he left",pos:"verb",gender:null,phonetic:"zhuh muh duh-MOND poor-KWAH eel eh par-TEE",note:"Se demander = to wonder. Same indirect rules.\nPourquoi stays, no inversion after it.",example:"A: Marc n'est plus là.\nB: Je me demande pourquoi il est parti.\nA: Tu penses qu'il était fâché?\nB: Je ne sais pas ce qui s'est passé.",exampleSrc:"A: Marc is no longer here.\nB: I wonder why he left.\nA: Do you think he was angry?\nB: I don't know what happened.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Comment s'appelle-t-il?' → Je ne sais pas _____",opts:["comment il s'appelle","comment s'appelle-t-il","ce que il s'appelle","si il s'appelle"],ans:"comment il s'appelle",hint:"In the indirect form, the question word stays but word order becomes standard."},
        {type:"fb",opts:["quand","si","ce que","où"],hint:"The original question was about timing or a specific moment.",s:"Il demande {1} nous partons en vacances.",a:["quand"]},
        {type:"drag_fill",hint:"What we are doing: the what is the object, then normal subject-verb order.",s:"Elle veut savoir {1} {2} {3} ce soir.",blanks:{"1":"ce","2":"que","3":"nous faisons"},pool:["ce","que","nous faisons","qui","si","faisons nous"]},
        {type:"mc",q:"Which is INCORRECT as an indirect question?",opts:["Il demande où vas-tu","Il demande où tu vas","Il demande si tu viens","Il demande ce que tu fais"],ans:"Il demande où vas-tu",hint:"One of these keeps the inverted word order from the direct question."},
        {type:"fb",opts:["ce qui","ce que","si","qui"],hint:"The what is the subject performing the action of breaking.",s:"Je me demande {1} a cassé la fenêtre.",a:["ce qui"]},
        {type:"drag_fill",hint:"A yes/no question about wanting uses the conjunction plus normal word order.",s:"Il demande {1} {2} {3} du café.",blanks:{"1":"si","2":"tu","3":"veux"},pool:["si","tu","veux","ce que","veut","que"]},
        {type:"mc",q:"'Qu'est-ce que tu as acheté?' → Il a demandé ce que _____",opts:["tu avais acheté","tu as acheté","tu achetais","tu achètes"],ans:"tu avais acheté",hint:"The reporting verb is past tense, so the reported clause shifts back one step."}
  ]},
  {id:"fre20l8",title:"Passif & Discours Indirect: Révision",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Passif & Discours Indirect: Révision",desc:"Combine everything from this unit: passive voice across tenses, passive alternatives, reported speech in present and past, and indirect questions.",goals:["Use passive voice confidently in all tenses","Report speech with correct tense shifts","Convert questions to indirect form","Choose between passive and active alternatives"]},
        {type:"mc",q:"Convert to passive: 'Le directeur a signé le contrat.'",opts:["Le contrat a été signé par le directeur","Le contrat est signé par le directeur","Le contrat sera signé par le directeur","Le directeur a été signé par le contrat"],ans:"Le contrat a été signé par le directeur",hint:"The original verb is in passé composé, so keep that tense in the conversion."},
        {type:"fb",opts:["qu'il","que il","qu'elle","si"],hint:"The conjunction elides before the pronoun that replaces the original speaker.",s:"Il a dit {1} ne pourrait pas venir.",a:["qu'il"]},
        {type:"mc",q:"'On m'a dit de partir.' What construction replaces passive here?",opts:["On + active verb","Pronominal passive","Se faire + infinitive","Standard passive"],ans:"On + active verb",hint:"The impersonal pronoun on takes the active role in this alternative."},
        {type:"drag_fill",hint:"A yes/no question in past reported speech: the auxiliary shifts to imparfait.",s:"Elle a demandé {1} {2} {3} terminé le projet.",blanks:{"1":"si","2":"nous","3":"avions"},pool:["si","nous","avions","que","avons","ce que"]},
        {type:"mc",q:"'Les fenêtres seront nettoyées la semaine prochaine.' This passive is in which tense?",opts:["Future","Present","Passé composé","Imparfait"],ans:"Future",hint:"The auxiliary form seront tells you when the action will take place."},
        {type:"fb",opts:["mange","manger","mangé","mangent"],hint:"The pronominal passive uses the present tense third person singular form.",s:"Ce plat se {1} avec du riz.",a:["mange"]},
        {type:"teach",trg:"Il m'a demandé ce que je voulais",src:"He asked me what I wanted",pos:"verb",gender:null,phonetic:"eel mah duh-mon-DEH suh kuh zhuh voo-LEH",note:"Indirect question in the past: ce que + imparfait.\nDirect: Qu'est-ce que vous voulez?\nShifted: ce que je voulais.",example:"A: Le serveur est venu.\nB: Qu'est-ce qu'il a dit?\nA: Il m'a demandé ce que je voulais.\nB: Et toi, qu'est-ce que tu as répondu?",exampleSrc:"A: The waiter came.\nB: What did he say?\nA: He asked me what I wanted.\nB: And what did you answer?",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"Which is the most natural spoken alternative for 'Ma voiture a été réparée'?",opts:["J'ai fait réparer ma voiture","Ma voiture est réparée par le mécanicien","On a réparé ma voiture","Ma voiture se répare"],ans:"J'ai fait réparer ma voiture",hint:"The construction with faire + infinitive expresses having something done for you."},
        {type:"match",pairs:[
          {trg:"Le livre est lu",src:"Passive present"},
          {trg:"Il dit qu'il est content",src:"Indirect speech present"},
          {trg:"Il a dit qu'il était content",src:"Indirect speech past"},
          {trg:"On parle français ici",src:"Active alternative to passive"}
        ]},
        {type:"drag_fill",hint:"A completed past event with a masculine singular subject needs three elements.",s:"Le suspect {1} {2} {3} hier par la police.",blanks:{"1":"a","2":"été","3":"interrogé"},pool:["a","été","interrogé","est","sera","interrogés"]},
        {type:"mc",q:"Il a dit: 'Je ferai les courses et je préparerai le dîner.' becomes:",opts:["Il a dit qu'il ferait les courses et qu'il préparerait le dîner","Il a dit qu'il fait les courses et qu'il prépare le dîner","Il a dit qu'il faisait les courses et qu'il préparait le dîner","Il a dit qu'il fera les courses et qu'il préparera le dîner"],ans:"Il a dit qu'il ferait les courses et qu'il préparerait le dîner",hint:"Both future verbs shift to the same conditional form in past reported speech."},
        {type:"fb",opts:["qui","ce qui","ce que","si"],hint:"The question is about a specific person, not a thing or event.",s:"Je ne sais pas {1} a pris mes clés.",a:["qui"]},
        {type:"mc",q:"'Trois personnes ont été blessées dans l'accident.' Why is passive used?",opts:["To focus on the victims and the event","Because active is grammatically wrong","To identify who caused the accident","Because French always uses passive for accidents"],ans:"To focus on the victims and the event",hint:"The construction puts emphasis on those affected rather than who is responsible."},
        {type:"drag_fill",hint:"The question word stays the same, pronouns shift, and no extra word is needed before the verb.",s:"Elle a demandé {1} {2} {3} habitions.",blanks:{"1":"où","2":"nous","3":""},pool:["où","nous","ce que","si","habitons"]},
        {type:"fb",opts:["sera","est","a été","était"],hint:"Le mois prochain tells you the action has not happened yet.",s:"Le nouveau musée {1} inauguré le mois prochain.",a:["sera"]},
        {type:"mc",q:"Convert to indirect: 'Est-ce que le train est arrivé?'",opts:["Il demande si le train est arrivé","Il demande que le train est arrivé","Il demande ce que le train est arrivé","Il demande le train si est arrivé"],ans:"Il demande si le train est arrivé",hint:"For yes/no questions, the linking word replaces est-ce que entirely."},
        {type:"drag_fill",hint:"Passé composé shifts: est partie becomes the imparfait auxiliary plus the participle.",s:"Il m'a dit {1} {2} {3} déjà partie.",blanks:{"1":"qu'","2":"elle","3":"était"},pool:["qu'","elle","était","que","il","est"]},
        {type:"mc",q:"Which combines passive AND past reported speech correctly?",opts:["Il a dit que le pont avait été construit en 2010","Il a dit que le pont a été construit en 2010","Il dit que le pont avait été construit en 2010","Il a dit que le pont sera construit en 2010"],ans:"Il a dit que le pont avait été construit en 2010",hint:"Past reporting verb means the passive construction also shifts back one step."}
  ]},
  {id:"fre20l8b",title:"Le Droit et les Finances",icon:"⚖️",xp:20,board:true,steps:[
        {type:"intro",title:"Legal & Financial Basics",desc:"Les mots essentiels du droit et des finances.\nLearn basic legal and financial vocabulary in French.",goals:["Learn 12 legal and financial words","Discuss money and contracts in French","Handle basic financial situations"]},
        {type:"teach",trg:"le contrat",src:"the contract",pos:"noun",gender:"m",note:"le contrat (m.)\nsigner un contrat (to sign a contract).\nun contrat de travail (employment contract).",example:"A: Tu as signé le contrat ?\nB: Pas encore, je veux le relire d'abord.\nA: Tu as raison, c'est important.\nB: Je vais le signer demain.",exampleSrc:"A: Did you sign the contract?\nB: Not yet, I want to reread it first.\nA: You're right, it's important.\nB: I'll sign it tomorrow.",funFact:"Cognate with English 'contract'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'assurance",src:"the insurance",pos:"noun",gender:"m",note:"l'assurance (f.)\nl'assurance maladie (health insurance).\nl'assurance auto (car insurance).",example:"A: Tu as une assurance santé ?\nB: Oui, c'est obligatoire en France.\nA: Et une assurance habitation ?\nB: Aussi, pour mon appartement.",exampleSrc:"A: Do you have health insurance?\nB: Yes, it's mandatory in France.\nA: And home insurance?\nB: Also, for my apartment.",funFact:"Cognate with English 'insurance'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'impôt",src:"the tax",pos:"noun",gender:"m",note:"l'impôt (m.)\nPlural: les impôts.\nla déclaration d'impôts (tax return).\npayer des impôts (to pay taxes).",example:"A: Tu as fait ta déclaration d'impôts ?\nB: Oui, en ligne, c'est plus simple.\nA: Tu paies beaucoup d'impôts ?\nB: Ça dépend de l'année.",exampleSrc:"A: Did you file your tax return?\nB: Yes, online, it's simpler.\nA: Do you pay a lot of taxes?\nB: It depends on the year.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la banque",src:"the bank",pos:"noun",gender:"f",note:"la banque (f.)\nun compte en banque (bank account).\nle/la banquier/banquière (banker).",example:"A: Tu vas à la banque aujourd'hui ?\nB: Oui, je dois ouvrir un nouveau compte.\nA: Quelle banque as-tu choisie ?\nB: La BNP, on me l'a recommandée.",exampleSrc:"A: Are you going to the bank today?\nB: Yes, I need to open a new account.\nA: Which bank did you choose?\nB: BNP, it was recommended to me.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le loyer",src:"the rent",pos:"noun",gender:"m",note:"le loyer (m.)\npayer le loyer (to pay the rent).\ncharges comprises (utilities included).",example:"A: Combien tu paies de loyer par mois ?\nB: 800 euros, charges comprises.\nA: C'est raisonnable pour Paris.\nB: Oui, j'ai eu de la chance.",exampleSrc:"A: How much rent do you pay per month?\nB: 800 euros, charges included.\nA: That's reasonable for Paris.\nB: Yes, I was lucky.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le prêt",src:"the loan",pos:"noun",gender:"m",note:"le prêt (m.)\nAlso: l'emprunt (m.) (borrowing, loan).\nun prêt immobilier (mortgage).",example:"A: Tu as demandé un prêt à la banque ?\nB: Oui, pour acheter un appartement.\nA: Quel est le taux d'intérêt ?\nB: 2,5 pour cent sur 20 ans.",exampleSrc:"A: Did you apply for a loan at the bank?\nB: Yes, to buy an apartment.\nA: What's the interest rate?\nB: 2.5 percent over 20 years.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"les économies",src:"the savings",pos:"noun",gender:"pl",note:"les économies (f. pl.)\nAlso: l'épargne (f.) (savings).\néconomiser (to save money).\nfaire des économies (to save money).",example:"A: Tu as des économies ?\nB: Oui, un peu sur mon livret A.\nA: C'est bien de mettre de l'argent de côté.\nB: J'essaie d'économiser chaque mois.",exampleSrc:"A: Do you have savings?\nB: Yes, a little in my savings account.\nA: It's good to put money aside.\nB: I try to save every month.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"les intérêts",src:"the interest (financial)",pos:"noun",gender:"pl",note:"les intérêts (m. pl.)\nle taux d'intérêt (interest rate).\npayer des intérêts (to pay interest).",example:"A: Le taux d'intérêt est de 3 pour cent.\nB: C'est un bon taux pour un prêt.\nA: Oui, les intérêts ne sont pas trop élevés.\nB: Je vais accepter cette offre.",exampleSrc:"A: The interest rate is 3 percent.\nB: That's a good rate for a loan.\nA: Yes, the interest isn't too high.\nB: I'm going to accept this offer.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"l'amende",src:"the fine / penalty",pos:"noun",gender:"m",note:"l'amende (f.)\npayer une amende (to pay a fine).\nrecevoir une amende (to receive a fine).",example:"A: J'ai reçu une amende de stationnement.\nB: Combien tu dois payer ?\nA: 35 euros.\nB: Ce n'est pas trop grave. Paie-la vite.",exampleSrc:"A: I got a parking fine.\nB: How much do you have to pay?\nA: 35 euros.\nB: That's not too bad. Pay it quickly.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la loi",src:"the law",pos:"noun",gender:"f",note:"la loi (f.)\nrespecter la loi (to obey the law).\nune nouvelle loi (a new law).",example:"A: C'est interdit par la loi.\nB: Vraiment ? Je ne savais pas.\nA: Oui, c'est une loi récente.\nB: Il faut se tenir informé.",exampleSrc:"A: It's forbidden by law.\nB: Really? I didn't know.\nA: Yes, it's a recent law.\nB: You have to stay informed.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le salaire",src:"the salary / wages",pos:"noun",gender:"m",note:"le salaire (m.)\nle salaire minimum (minimum wage).\nle salaire brut/net (gross/net salary).",example:"A: Le salaire minimum a augmenté.\nB: Oui, depuis le premier janvier.\nA: C'est une bonne nouvelle pour beaucoup de gens.\nB: C'est vrai, mais les prix augmentent aussi.",exampleSrc:"A: The minimum wage has increased.\nB: Yes, since January 1st.\nA: That's good news for many people.\nB: True, but prices are going up too.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le reçu",src:"the receipt",pos:"noun",gender:"m",note:"le reçu (m.)\ngarder le reçu (to keep the receipt).\nAlso: le ticket de caisse (cash register receipt).",example:"A: Vous avez le reçu ?\nB: Oui, le voici.\nA: Merci, je dois le garder pour les impôts.\nB: C'est toujours utile de garder ses reçus.",exampleSrc:"A: Do you have the receipt?\nB: Yes, here it is.\nA: Thanks, I need to keep it for taxes.\nB: It's always useful to keep your receipts.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"tip",title:"Money and Banking in French",deepDive:"French financial vocabulary:\n\nle relevé de compte (bank statement).\nla carte bancaire (bank card).\nle chèque (check).\nles frais bancaires (bank fees).\n\nIn France, card payments are very common. The carte bancaire (CB) is the most used payment method.",text:"Common financial expressions:\n\nouvrir un compte (to open an account).\nfaire un virement (to make a transfer).\nretirer de l'argent (to withdraw money).\ndéposer de l'argent (to deposit money).\nle distributeur (ATM)."},
        {type:"mc",q:"Which word means 'the contract' in French?",opts:["le contrat","le loyer","le prêt","le reçu"],ans:"le contrat",hint:"A formal written agreement between two parties."},
        {type:"mc",q:"'L'amende' means:",opts:["the fine","the loan","the tax","the savings"],ans:"the fine",hint:"A payment you must make as punishment for breaking a rule."},
        {type:"fb",opts:["loyer","prêt","impôt","contrat"],hint:"The monthly amount you pay to live in a rented place.",s:"Je paie un {1} de 900 euros par mois pour mon appartement.",a:["loyer"]},
        {type:"fb",opts:["prêt","impôt","reçu","loyer"],hint:"Money borrowed from a bank that you pay back over time.",s:"Elle a demandé un {1} à la banque pour acheter une voiture.",a:["prêt"]},
        {type:"mc",q:"What does 'les économies' mean?",opts:["the savings","the taxes","the interest","the receipts"],ans:"the savings",hint:"Money put aside for the future, not spent immediately."},
        {type:"match",pairs:[{trg:"l'impôt",src:"the tax"},{trg:"la banque",src:"the bank"},{trg:"la loi",src:"the law"},{trg:"le reçu",src:"the receipt"},{trg:"l'assurance",src:"the insurance"}]},
        {type:"fb",opts:["impôts","intérêts","économies","amendes"],hint:"Annual payment to the government based on your income.",s:"Tu as fait ta déclaration d'{1} cette année ?",a:["impôts"]},
        {type:"drag_fill",hint:"After signing the agreement, you got proof of payment from the financial institution.",s:"J'ai signé le {1} et j'ai reçu le {2} de la {3}.",blanks:{"1":"contrat","2":"reçu","3":"banque"},pool:["contrat","reçu","banque","amende"]},
        {type:"mc",q:"How do you say 'to save money' in French?",opts:["faire des économies","payer des impôts","signer un contrat","recevoir une amende"],ans:"faire des économies",hint:"An expression using the plural of the word for savings."}
  ]}
]};
